mapper.select:
SELECT w.*, sp.name AS part_name
FROM ai_weekly_forecast w
LEFT JOIN spare_part sp ON sp.code = w.part_code

    AND w.part_code LIKE CONCAT('%', #{partCode}, '%')
    AND w.week_start >= #{weekStart}
    AND w.algo_type = #{algoType}

ORDER BY w.week_start DESC, w.part_code ASC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM ai_weekly_forecast w

    AND w.part_code LIKE CONCAT('%', #{partCode}, '%')
    AND w.week_start >= #{weekStart}
    AND w.algo_type = #{algoType}
